patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c06d5c759634..7003139d3608 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1065,7 +1065,8 @@ static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,
                                          InstCombiner::BuilderTy &Builder) {
   Value *ZeroCmpOp;
   ICmpInst::Predicate EqPred;
-  if (!match(ZeroICmp, m_ICmp(EqPred, m_Value(ZeroCmpOp), m_Zero())) ||
+  const APInt *C;
+  if (!match(ZeroICmp, m_ICmp(EqPred, m_Value(ZeroCmpOp), m_APIntAllowUndef(C))) ||
       !ICmpInst::isEquality(EqPred))
     return nullptr;

@@ -1076,27 +1077,40 @@ static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,
   ICmpInst::Predicate UnsignedPred;

   Value *A, *B;
-  if (match(UnsignedICmp,
-            m_c_ICmp(UnsignedPred, m_Specific(ZeroCmpOp), m_Value(A))) &&
-      match(ZeroCmpOp, m_c_Add(m_Specific(A), m_Value(B))) &&
-      (ZeroICmp->hasOneUse() || UnsignedICmp->hasOneUse())) {
-    auto GetKnownNonZeroAndOther = [&](Value *&NonZero, Value *&Other) {
-      if (!IsKnownNonZero(NonZero))
-        std::swap(NonZero, Other);
-      return IsKnownNonZero(NonZero);
-    };
+  if (C->isZero()) {
+    if (match(UnsignedICmp,
+              m_c_ICmp(UnsignedPred, m_Specific(ZeroCmpOp), m_Value(A))) &&
+        match(ZeroCmpOp, m_c_Add(m_Specific(A), m_Value(B))) &&
+        (ZeroICmp->hasOneUse() || UnsignedICmp->hasOneUse())) {
+      auto GetKnownNonZeroAndOther = [&](Value *&NonZero, Value *&Other) {
+        if (!IsKnownNonZero(NonZero))
+          std::swap(NonZero, Other);
+        return IsKnownNonZero(NonZero);
+      };
+
+      // Given  ZeroCmpOp = (A + B)
+      //   ZeroCmpOp <  A && ZeroCmpOp != 0  -->  (0-X) <  Y  iff
+      //   ZeroCmpOp >= A || ZeroCmpOp == 0  -->  (0-X) >= Y  iff
+      //     with X being the value (A/B) that is known to be non-zero,
+      //     and Y being remaining value.
+      if (UnsignedPred == ICmpInst::ICMP_ULT && EqPred == ICmpInst::ICMP_NE &&
+          IsAnd && GetKnownNonZeroAndOther(B, A))
+        return Builder.CreateICmpULT(Builder.CreateNeg(B), A);
+      if (UnsignedPred == ICmpInst::ICMP_UGE && EqPred == ICmpInst::ICMP_EQ &&
+          !IsAnd && GetKnownNonZeroAndOther(B, A))
+        return Builder.CreateICmpUGE(Builder.CreateNeg(B), A);
+    }
+  }

-    // Given  ZeroCmpOp = (A + B)
-    //   ZeroCmpOp <  A && ZeroCmpOp != 0  -->  (0-X) <  Y  iff
-    //   ZeroCmpOp >= A || ZeroCmpOp == 0  -->  (0-X) >= Y  iff
-    //     with X being the value (A/B) that is known to be non-zero,
-    //     and Y being remaining value.
-    if (UnsignedPred == ICmpInst::ICMP_ULT && EqPred == ICmpInst::ICMP_NE &&
-        IsAnd && GetKnownNonZeroAndOther(B, A))
-      return Builder.CreateICmpULT(Builder.CreateNeg(B), A);
-    if (UnsignedPred == ICmpInst::ICMP_UGE && EqPred == ICmpInst::ICMP_EQ &&
-        !IsAnd && GetKnownNonZeroAndOther(B, A))
-      return Builder.CreateICmpUGE(Builder.CreateNeg(B), A);
+  // (A != C) & (A + -C <= B) -> A + -C - 1 < B
+  // (A == C) | (A + -C >  B) -> A + -C - 1 >= B
+  Value *C2;
+  if (match(UnsignedICmp, m_c_ICmp(UnsignedPred, m_c_Add(m_Specific(ZeroCmpOp), m_SpecificInt(-*C)), m_Value(C2))) &&
+      (ZeroICmp->hasOneUse() || UnsignedICmp->hasOneUse())) {
+    if (UnsignedPred == ICmpInst::ICMP_ULE && EqPred == ICmpInst::ICMP_NE && IsAnd)
+      return Builder.CreateICmpULT(Builder.CreateAdd(ZeroCmpOp, ConstantInt::get(ZeroCmpOp->getType(), -*C - 1)), C2);
+    if (UnsignedPred == ICmpInst::ICMP_UGT && EqPred == ICmpInst::ICMP_EQ && !IsAnd)
+      return Builder.CreateICmpUGE(Builder.CreateAdd(ZeroCmpOp, ConstantInt::get(ZeroCmpOp->getType(), -*C - 1)), C2);
   }

   Value *Base, *Offset;

