{"command":"cat <<'CODEEOF' | cd /data/zrwang/auto-opt/utils/llvm-63749 && python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp 1108 1120
  // (A != -1) & (A + 1 <= B) -> A < B
  // (A == -1) | (A + 1 >  B) -> A >= B
  if (match(ZeroICmp->getOperand(1), m_AllOnes())) {
    Value *C;
    if (match(UnsignedICmp, m_ICmp(UnsignedPred, m_c_Add(m_Specific(ZeroCmpOp), m_One()), m_Value(C))) &&
